Here's an updated `BaseRepository` class that allows you to find by a dynamic field:

```csharp
public abstract class BaseRepository<TEntity, TPrimaryKey> : IRepository<TEntity, TPrimaryKey> 
    where TEntity : class, IEntity<TPrimaryKey>
{
    // ... other methods ...

    public virtual async Task<TEntity> FindByDynamicAsync(TPrimaryKey primaryKey, string field, object value)
    {
        return await Context.Set<TEntity>()
            .Where(x => x.PrimaryKey.Equals(primaryKey))
            .Where(x => GetDynamicExpression(field).Contains(value))
            .FirstOrDefaultAsync();
    }

    private Expression<Func<TEntity, bool>> GetDynamicExpression(string field)
    {
        ParameterExpression parameter = Expression.Parameter(typeof(TEntity));
        MemberExpression member = Expression.PropertyOrField(parameter, field);

        return Expression.Lambda<Func<TEntity, bool>>(
            Expression.Equal(member, Expression.Constant(value)), parameter);
    }
}
```

